<?php require_once __DIR__.'/includes/layout.php'; render_header('商品庫');
$cat=$_GET['category']??''; $q=$_GET['q']??''; $sql='SELECT * FROM products WHERE 1'; $params=[];
if($cat){$sql.=' AND category=?';$params[]=$cat;} if($q){$sql.=' AND (name LIKE ? OR brand LIKE ? OR ingredients LIKE ?)';$params[]="%$q%";$params[]="%$q%";$params[]="%$q%";}
$sql.=' ORDER BY id DESC'; $st=db()->prepare($sql); $st->execute($params); $products=$st->fetchAll(); ?>
<h1>商品資料庫</h1><div class="panel"><form class="form" method="get"><div class="form-row"><input name="q" placeholder="搜尋品牌、商品、成分" value="<?=h($q)?>"><select name="category"><option value="">全部分類</option><?php foreach(['洗面乳','化妝水','精華液','乳液','防曬','痘痘護理'] as $c): ?><option <?= $cat===$c?'selected':'' ?>><?=h($c)?></option><?php endforeach; ?></select></div><button>搜尋</button></form></div><br><div class="products"><?php foreach($products as $p): ?><div class="product"><h3><?=h($p['brand'])?>｜<?=h($p['name'])?></h3><p><span class="tag"><?=h($p['category'])?></span><span class="tag"><?=h($p['skin_types'])?></span></p><p><?=h($p['description'])?></p><p class="small">成分：<?=h($p['ingredients'])?></p><div class="price">NT$ <?=h($p['price'])?></div><form method="post" action="favorite_action.php"><input type="hidden" name="product_id" value="<?=h($p['id'])?>"><button class="btn secondary">收藏</button></form></div><?php endforeach; ?></div><?php render_footer(); ?>
